class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        print(f"{self.name} makes a sound")

animal = Animal("Generic")
animal.speak()

class Dog(Animal):
    def bark(self):
        print(f"{self.name} says Woof!")

dog = Dog("Buddy")
dog.speak()
dog.bark()

class Dog(Animal):
    def speak(self):
        print(f"{self.name} barks: Woof!")

dog = Dog("Buddy")
dog.speak()

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)
        self.breed = breed

    def info(self):
        print(f"{self.name} is a {self.breed}")

dog = Dog("Buddy", "Labrador")
dog.info()
